SELECT USER_NO AS userNo, USER_NAME AS userName, EMAIL AS email, PHONE AS phone, PROVIDER AS provider, CREATED_AT AS createdAt, STATUS AS status, DELETE_AT AS deleteAt, AUTH AS auth FROM USERS WHERE 1 = 1
AND ( USER_NAME LIKE CONCAT('%', #{keyword}, '%') OR EMAIL LIKE CONCAT('%', #{keyword}, '%') OR PHONE LIKE CONCAT('%', #{keyword}, '%') )
AND STATUS = #{status}
AND AUTH = #{auth}
ORDER BY USER_NO DESC

